将 ey、ex、hz 更新循环融合为一个循环，并添加分块：
for(t = 0; t < _PB_TMAX; t++) {
  for (j = 0; j < _PB_NY; j++)
    ey[0][j] = _fict_[t];
  for (ii = 1; ii < _PB_NX; ii += TILE) {
    for (jj = 0; jj < _PB_NY; jj += TILE) {
      for (i = ii; i < min(ii+TILE, _PB_NX); i++) {
        for (j = jj; j < min(jj+TILE, _PB_NY); j++) {
          if (j == 0 && i > 0) ey[i][j] = ey[i][j] - 0.5*(hz[i][j]-hz[i-1][j]);
          else if (i > 0) ey[i][j] = ey[i][j] - 0.5*(hz[i][j]-hz[i-1][j]);
          if (i == 0 && j > 0) ex[i][j] = ex[i][j] - 0.5*(hz[i][j]-hz[i][j-1]);
          else if (j > 0) ex[i][j] = ex[i][j] - 0.5*(hz[i][j]-hz[i][j-1]);
          if (i < _PB_NX-1 && j < _PB_NY-1) hz[i][j] = hz[i][j] - 0.7*(ex[i][j+1] - ex[i][j] + ey[i+1][j] - ey[i][j]);
        }
      }
    }
  }
}

将三个独立的二维数组合并为结构体数组，并按列优先存储：
typedef struct { DATA_TYPE ex, ey, hz; } FieldPoint;
FieldPoint POLYBENCH_2D(field,NX,NY,nx,ny);
然后调整所有访问：field[i][j].ex, field[i][j].ey, field[i][j].hz

在内层循环中展开2-4次，并使用局部变量减少内存访问：
for (i = 1; i < _PB_NX-1; i+=2) {
  DATA_TYPE hz_curr = hz[i][j];
  DATA_TYPE hz_prev = hz[i-1][j];
  DATA_TYPE hz_next = hz[i+1][j];
  ey[i][j] = ey[i][j] - 0.5*(hz_curr - hz_prev);
  ey[i+1][j] = ey[i+1][j] - 0.5*(hz_next - hz_curr);
  // 类似处理 ex 和 hz 更新
}

